var WindowPanel = require('../../../com/window/windowpanel');

var IssueList = function(){};
WindowPanel._extend(IssueList, {
  _className : 'IssueList',
  __filename : __filename,
  title : '我的历史反馈',
  tplName : 'page/common/issuelist/issuelist',
  cssName : 'page/common/issuelist/issuelist',
  record : null,
  afterComplete : function(){
    IssueList.prototype._super.afterComplete.call(this);
    var _self = this;
    $(_self.el).css('position', 'fixed');
    var list = this.query('list');
    list.store.load(_self.record);
  },
  initEvents : function(){
    IssueList.prototype._super.initEvents.call(this);
    var _self = this;
    $('.feed_back_fixed').on('click', function(){
      $(_self.el).remove();
    });
  }

});
exports = module.exports = IssueList;

